328→              value={buyerName}
329→              onChange={(e) => setBuyerName(e.target.value)}
330→              disabled={formLocked}
331→            />
332→          </label>
333→          <label className="grid gap-1">
334→            <span className="text-xs font-medium text-[color:var(--lr-muted)]">
335→              Phone (optional)
336→            </span>
337→            <input
338→              className="lr-field px-3 py-2 text-sm"
339→              type="tel"
340→              value={buyerPhone}
341→              onChange={(e) => setBuyerPhone(e.target.value)}
342→              disabled={formLocked}
343→              placeholder="(555) 555-1234"
344→            />
345→          </label>
346→        </div>
347→
348→        <button
349→          type="submit"
350→          className={`lr-btn lr-btn-primary mt-2 inline-flex items-center justify-center px-4 py-2 text-sm font-medium disabled:opacity-50${checkout ? " cursor-not-allowed" : ""}`}
351→          disabled={submitting || items.length === 0 || !buyerEmail.trim() || !!checkout}
352→        >
353→          {checkout
354→            ? "Complete payment below"
355→            : submitting
356→              ? "Starting\u2026"
357→              : "Continue to payment"}
358→        </button>
359→        {checkout ? (
360→          <AuthorizeCard
361→            clientSecret={checkout.client_secret}
362→            submitting={submitting}
363→            setSubmitting={setSubmitting}
364→            setError={setError}
365→            onAuthorized={completeCardOrder}
366→            mode="payment_intent"
367→          />
368→        ) : null}
369→      </form>
370→    </section>
371→  );
372→}
