  1→"use client";
  2→
  3→import Link from "next/link";
  4→import { useMemo, useRef, useState } from "react";
  5→import type { SubscriptionPlan } from "@/lib/api";
  6→import { buyerApi, type PlanCheckoutResponse, type SubscribeResponse } from "@/lib/buyer-api";
  7→import { orderToken } from "@/lib/order-token";
  8→import { subscriptionToken } from "@/lib/subscription-token";
  9→import { PickupCodeCard } from "@/components/pickup-code-card";
 10→import { useToast } from "@/components/toast";
 11→import { cadenceLabel, formatMoney, friendlyErrorMessage } from "@/lib/ui";
 12→import { AuthorizeCard, isStripeAvailable } from "@/components/stripe-card-auth";
 13→import { ErrorAlert } from "@/components/error-alert";
 14→
 15→export function SubscribeForm({ plan }: { plan: SubscriptionPlan }) {
 16→  const { showToast } = useToast();
 17→  const [email, setEmail] = useState("");
 18→  const [name, setName] = useState("");
 19→  const [phone, setPhone] = useState("");
 20→  const [showOptional, setShowOptional] = useState(false);
 21→  const [submitting, setSubmitting] = useState(false);
 22→  const [error, setError] = useState<string | null>(null);
 23→  const [done, setDone] = useState<SubscribeResponse | null>(null);
 24→  const [checkout, setCheckout] = useState<PlanCheckoutResponse | null>(null);
 25→  const startingCheckoutRef = useRef(false);
 26→
 27→  const paymentsReady = Boolean(process.env.NEXT_PUBLIC_STRIPE_PUBLISHABLE_KEY);
 28→  const formLocked = !!checkout;
 29→  const priceSubtotal = checkout?.subtotal_cents ?? plan.price_cents;
 30→  const priceFee = checkout?.buyer_fee_cents ?? 0;
 31→  const priceTotal = checkout?.total_cents ?? plan.price_cents;
 32→  const depositCents = checkout?.deposit_cents ?? plan.deposit_cents ?? 0;
 33→  const feeBps = checkout?.buyer_fee_bps ?? null;
 34→  const feeFlat = checkout?.buyer_fee_flat_cents ?? null;
 35→  const feeLabel = (() => {
 36→    const parts: string[] = [];
 37→    if (feeBps !== null && feeBps > 0) parts.push(`${(feeBps / 100).toFixed(0)}%`);
 38→    if (feeFlat !== null && feeFlat > 0) parts.push(formatMoney(feeFlat));
 39→    return parts.length > 0 ? parts.join(" + ") : null;
 40→  })();
 41→
 42→  const nextLabel = useMemo(() => {
 43→    const tz = plan.pickup_location.timezone || "UTC";
 44→    const start = new Date(plan.next_start_at);
 45→    return new Intl.DateTimeFormat("en-US", {
 46→      timeZone: tz,
 47→      weekday: "short",
 48→      month: "short",
 49→      day: "numeric",
 50→      hour: "numeric",
 51→      minute: "2-digit",
 52→    }).format(start);
 53→  }, [plan.next_start_at, plan.pickup_location.timezone]);
 54→
 55→  async function startCheckout() {
 56→    if (startingCheckoutRef.current) return;
 57→    if (!isStripeAvailable()) {
 58→      setError("Payment system could not load. Please disable ad blockers and refresh.");
 59→      return;
 60→    }
 61→    startingCheckoutRef.current = true;
 62→    setSubmitting(true);
 63→    setError(null);
 64→    try {
 65→      const res = await buyerApi.checkoutPlan(plan.id, {
 66→        buyer: {
 67→          email,
 68→          name: name || null,
 69→          phone: phone || null,
 70→        },
 71→      });
 72→      setCheckout(res);
 73→      showToast({
 74→        kind: "success",
 75→        message:
 76→          res.mode === "payment_intent"
 77→            ? "Card authorization started."
 78→            : "Card setup started.",
 79→      });
 80→    } catch (e: unknown) {
 81→      setError(friendlyErrorMessage(e));
 82→    } finally {
 83→      setSubmitting(false);
 84→      startingCheckoutRef.current = false;
 85→    }
 86→  }
 87→
 88→  async function completeSubscribe() {
 89→    if (!checkout) return;
 90→    try {
 91→      const res = await buyerApi.subscribeToPlan(plan.id, {
 92→        payment_intent_id: checkout.mode === "payment_intent" ? checkout.id : undefined,
 93→        setup_intent_id: checkout.mode === "setup_intent" ? checkout.id : undefined,
 94→        buyer: {
 95→          email,
 96→          name: name || null,
 97→          phone: phone || null,
 98→        },
 99→      });
100→      subscriptionToken.set(res.subscription.id, res.subscription.buyer_token);
101→      orderToken.set(res.first_order.id, res.first_order.buyer_token);
102→      setDone(res);
103→      setCheckout(null);
104→      showToast({ kind: "success", message: "Subscription started." });
105→    } catch {
106→      // Card is already authorized — keep checkout state so user can retry
107→      // without re-authorizing their card.
108→      setError(
